import React, { useState, useRef, useMemo, useCallback } from 'react';
import { useRouter } from '../../hooks/useRouter';
import { ChevronDown, ArrowRight, FileText, Layers, Box, Settings, Factory, ShieldCheck, ChevronRight as ChevronRightIcon } from 'lucide-react';
import { PRODUCT_CATEGORIES } from '../../lib/constants';
import { useTranslation } from 'react-i18next';

export interface NavLinkData {
    key?: string;
    text: string;
    href: string;
}

interface NavLinksProps {
  className?: string;
  links: NavLinkData[];
  onLinkClick?: () => void;
  isMobile?: boolean; 
  isScrolled?: boolean;
}

export const NavLinks: React.FC<NavLinksProps> = ({ className = '', links, onLinkClick, isMobile = false, isScrolled = false }) => {
    const { t } = useTranslation();
    const currentHash = useRouter();
    const [hoveredLink, setHoveredLink] = useState<string | null>(null);
    const [activeGroup, setActiveGroup] = useState<string>('tubular'); 
    const closeTimeoutRef = useRef<number | null>(null);

    const PRODUCT_GROUPS = useMemo(() => [
        {
            id: 'tubular',
            label: t('header.mobileGroups.tubular'),
            icon: <Layers size={18} />,
            description: t('header.mobileGroups.tubularDesc'),
            items: ['tubes', 'conduits', 'grooved']
        },
        {
            id: 'conexoes',
            label: t('header.mobileGroups.connections'),
            icon: <Settings size={18} />,
            description: t('header.mobileGroups.connectionsDesc'),
            items: ['flanges', 'fittings', 'valves']
        },
        {
            id: 'estrutural',
            label: t('header.mobileGroups.structural'),
            icon: <Box size={18} />,
            description: t('header.mobileGroups.structuralDesc'),
            items: ['profiles', 'plates', 'gratings', 'tiles', 'civil']
        },
        {
            id: 'industrial',
            label: t('header.mobileGroups.industrial'),
            icon: <Factory size={18} />,
            description: t('header.mobileGroups.industrialDesc'),
            items: ['boilermaking', 'cutting', 'tanks']
        }
    ], [t]);

    const handleMouseEnter = useCallback((key: string) => {
        if (closeTimeoutRef.current) {
            clearTimeout(closeTimeoutRef.current);
            closeTimeoutRef.current = null;
        }
        setHoveredLink(key);
    }, []);

    const handleMouseLeave = useCallback(() => {
        closeTimeoutRef.current = window.setTimeout(() => {
            setHoveredLink(null);
        }, 200);
    }, []);

    const isActive = (href: string): boolean => {
        if (href === '#/') return currentHash === '' || currentHash === '#/';
        return currentHash.startsWith(href);
    };

    const currentGroupProducts = useMemo(() => {
        const group = PRODUCT_GROUPS.find(g => g.id === activeGroup);
        return group ? PRODUCT_CATEGORIES.filter(prod => group.items.includes(prod.id)) : [];
    }, [activeGroup, PRODUCT_GROUPS]);

    if (isMobile) return null;

    return (
        <nav 
            className={`flex flex-row items-center space-x-1 ${className}`}
            onMouseLeave={handleMouseLeave}
        >
             {links.map((link) => {
                 const active = isActive(link.href);
                 const isProducts = link.key === 'products';
                 const isMegaMenuOpen = isProducts && hoveredLink === 'products';

                 return (
                    <div 
                        key={link.href} 
                        className="relative"
                        onMouseEnter={() => handleMouseEnter(link.key || '')}
                    >
                        <a 
                            href={link.href} 
                            onClick={onLinkClick}
                            className={`
                                relative flex items-center justify-start gap-1 transition-colors duration-200 whitespace-nowrap
                                px-4 py-4 text-xs font-bold tracking-widest text-gray-300 hover:text-white uppercase
                                ${active ? 'text-brand-orange' : ''}
                            `}
                        >
                            {link.text}
                            {isProducts && (
                                <ChevronDown 
                                    size={12} 
                                    className={`transition-transform duration-300 ease-out ${isMegaMenuOpen ? 'rotate-180 text-brand-orange' : ''}`} 
                                />
                            )}
                            <span className={`absolute bottom-3 left-4 right-4 h-[2px] bg-brand-orange transform origin-left transition-transform duration-300 ease-out ${active || hoveredLink === link.key ? 'scale-x-100' : 'scale-x-0'}`}></span>
                        </a>

                        {isProducts && (
                            <div 
                                className={`
                                    absolute left-1/2 -translate-x-1/2 w-[90vw] max-w-6xl z-[60] pt-2
                                    transition-all duration-300 cubic-bezier(0.16, 1, 0.3, 1) origin-top
                                    ${isMegaMenuOpen 
                                        ? 'opacity-100 scale-100 visible translate-y-0' 
                                        : 'opacity-0 scale-[0.99] invisible -translate-y-2 pointer-events-none'
                                    }
                                `}
                            >
                                <div className="bg-white rounded-2xl shadow-[0_30px_90px_-15px_rgba(0,0,0,0.3)] border-t-[4px] border-brand-orange overflow-hidden ring-1 ring-black/5">
                                    <div className="flex h-[380px]">

                                        {/* COL 1: SIDEBAR DE CATEGORIAS (DENSA) */}
                                        <div className="w-[240px] flex-shrink-0 bg-gray-50 border-r border-gray-100 p-3 flex flex-col gap-1">
                                            <div className="text-[9px] font-black text-gray-400 uppercase tracking-[0.25em] px-3 py-2 mb-1 opacity-70">
                                                {t('layout.departments')}
                                            </div>
                                            {PRODUCT_GROUPS.map((group) => (
                                                <button
                                                    key={group.id}
                                                    onMouseEnter={() => setActiveGroup(group.id)}
                                                    className={`
                                                        text-left px-3.5 py-2.5 rounded-lg transition-all duration-150 group/btn flex items-center gap-3 relative
                                                        ${activeGroup === group.id 
                                                            ? 'bg-white shadow-sm text-brand-blue-dark border border-gray-200' 
                                                            : 'text-gray-500 hover:bg-gray-200/50 hover:text-brand-blue-dark'
                                                        }
                                                    `}
                                                >
                                                    {activeGroup === group.id && (
                                                        <span className="absolute left-0 top-2 bottom-2 w-1 bg-brand-orange rounded-r-full"></span>
                                                    )}
                                                    <div className={`transition-colors duration-150 ${activeGroup === group.id ? 'text-brand-orange' : 'text-gray-400'}`}>
                                                        {React.cloneElement(group.icon as React.ReactElement<{ size: number }>, { size: 16 })}
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <span className="block font-bold text-[13px] leading-none mb-0.5">{group.label}</span>
                                                        <span className="block text-[9px] opacity-60 font-semibold truncate uppercase tracking-tight">{group.description}</span>
                                                    </div>
                                                </button>
                                            ))}
                                        </div>

                                        {/* COL 2: GRID DE PRODUTOS (UNIDA) */}
                                        <div className="flex-1 px-8 py-5 bg-white flex flex-col min-w-0">
                                            <div className="flex justify-between items-center mb-3.5 border-b border-gray-50 pb-3">
                                                <div key={activeGroup} className="animate-in fade-in slide-in-from-left-1 duration-200">
                                                    <h3 className="text-lg font-black text-brand-blue-dark tracking-tight uppercase">
                                                        {PRODUCT_GROUPS.find(g => g.id === activeGroup)?.label}
                                                    </h3>
                                                </div>
                                                <a href="#/products" onClick={() => setHoveredLink(null)} className="text-[10px] font-black text-brand-orange hover:text-brand-blue-dark transition-colors flex items-center gap-1.5 group/all uppercase tracking-widest">
                                                    {t('layout.viewAll')} 
                                                    <ArrowRight size={12} className="group-hover/all:translate-x-1 transition-transform" />
                                                </a>
                                            </div>

                                            <div 
                                                key={`grid-${activeGroup}`}
                                                className="grid grid-cols-2 gap-x-2 gap-y-0.5 overflow-y-auto custom-scrollbar flex-1 pr-1"
                                            >
                                                {currentGroupProducts.map((cat, idx) => (
                                                    <a 
                                                        key={cat.id} 
                                                        href={cat.href} 
                                                        onClick={() => setHoveredLink(null)} 
                                                        className="group/card flex items-center gap-2.5 p-1.5 rounded-lg hover:bg-gray-50 transition-all duration-150 border border-transparent hover:border-gray-100"
                                                    >
                                                        <div className="w-10 h-10 flex-shrink-0 rounded-lg bg-gray-100 p-0.5 overflow-hidden border border-gray-100 group-hover/card:border-brand-orange/40 transition-colors">
                                                            <img src={cat.imageUrl} alt={cat.id} className="w-full h-full object-cover rounded-md" loading="eager" />
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <span className="block text-[10px] font-black text-gray-700 group-hover/card:text-brand-orange transition-colors uppercase tracking-wide truncate">
                                                                {t(`productsPage.categories.${cat.id}`)}
                                                            </span>
                                                            <span className="flex items-center text-[8px] text-gray-400 font-bold uppercase tracking-tighter opacity-80 group-hover/card:opacity-100 group-hover/card:text-brand-blue-dark">
                                                                {t('layout.viewSpecs')}
                                                                <ChevronRightIcon size={8} className="ml-1 opacity-0 group-hover/card:opacity-100 transform translate-x-[-4px] group-hover:translate-x-0 transition-all" />
                                                            </span>
                                                        </div>
                                                    </a>
                                                ))}
                                            </div>
                                        </div>

                                        {/* COL 3: CATÁLOGO (REFINADO) */}
                                        <div className="w-[260px] flex-shrink-0 bg-[#081437] p-6 flex flex-col justify-between relative overflow-hidden">
                                            {/* Glow decorativo sutil */}
                                            <div className="absolute -top-10 -right-10 w-32 h-32 bg-brand-orange/20 rounded-full blur-[40px]"></div>

                                            <div className="relative z-10">
                                                <div className="inline-flex p-2.5 rounded-xl bg-white/5 text-brand-orange mb-4 border border-white/10">
                                                    <FileText size={20} />
                                                </div>
                                                <h4 className="text-lg font-black text-white mb-2 tracking-tight uppercase leading-tight">{t('layout.catalogCall')}</h4>
                                                <p className="text-[11px] text-blue-100/60 leading-relaxed font-medium">
                                                    {t('layout.catalogDesc')}
                                                </p>
                                            </div>

                                            <div className="relative z-10 space-y-3">
                                                <div className="flex items-center gap-2 text-[9px] text-gray-500 font-black tracking-widest uppercase">
                                                    <ShieldCheck size={12} className="text-green-500" />
                                                    <span>{t('layout.updated')}</span>
                                                </div>
                                                <a 
                                                    href="#/catalog" 
                                                    onClick={() => setHoveredLink(null)} 
