import React, { useState, useRef, useMemo, useCallback } from 'react';
import { useRouter } from '../../hooks/useRouter';
import { ChevronDown, ArrowRight, FileText, Layers, Box, Settings, Factory, ShieldCheck, ChevronRight as ChevronRightIcon } from 'lucide-react';
import { PRODUCT_CATEGORIES } from '../../lib/constants';
import { useTranslation } from 'react-i18next';

export interface NavLinkData {
    key?: string;
    text: string;
    href: string;
}

interface NavLinksProps {
  className?: string;
  links: NavLinkData[];
  onLinkClick?: () => void;
  isMobile?: boolean; 
  isScrolled?: boolean;
}

export const NavLinks: React.FC<NavLinksProps> = ({ className = '', links, onLinkClick, isMobile = false, isScrolled = false }) => {
    const { t } = useTranslation();
    const currentHash = useRouter();
    const [hoveredLink, setHoveredLink] = useState<string | null>(null);
    const [activeGroup, setActiveGroup] = useState<string>('tubular'); 
    const closeTimeoutRef = useRef<number | null>(null);

    const PRODUCT_GROUPS = useMemo(() => [
        {
            id: 'tubular',
            label: t('header.mobileGroups.tubular'),
            icon: <Layers size={18} />,
            description: t('header.mobileGroups.tubularDesc'),
            items: ['tubes', 'conduits', 'grooved']
        },
        {
            id: 'conexoes',
            label: t('header.mobileGroups.connections'),
            icon: <Settings size={18} />,
            description: t('header.mobileGroups.connectionsDesc'),
            items: ['flanges', 'fittings', 'valves']
        },
        {
            id: 'estrutural',
            label: t('header.mobileGroups.structural'),
            icon: <Box size={18} />,
            description: t('header.mobileGroups.structuralDesc'),
            items: ['profiles', 'plates', 'gratings', 'tiles', 'civil']
        },
        {
            id: 'industrial',
            label: t('header.mobileGroups.industrial'),
            icon: <Factory size={18} />,
            description: t('header.mobileGroups.industrialDesc'),
            items: ['boilermaking', 'cutting', 'tanks']
        }
    ], [t]);

    const handleMouseEnter = useCallback((key: string) => {
        if (closeTimeoutRef.current) {
            clearTimeout(closeTimeoutRef.current);
            closeTimeoutRef.current = null;
        }
        setHoveredLink(key);
    }, []);

    const handleMouseLeave = useCallback(() => {
        closeTimeoutRef.current = window.setTimeout(() => {
            setHoveredLink(null);
        }, 200);
    }, []);

    const isActive = (href: string): boolean => {
        if (href === '#/') return currentHash === '' || currentHash === '#/';
        return currentHash.startsWith(href);
    };

    const currentGroupProducts = useMemo(() => {
        const group = PRODUCT_GROUPS.find(g => g.id === activeGroup);
        return group ? PRODUCT_CATEGORIES.filter(prod => group.items.includes(prod.id)) : [];
    }, [activeGroup, PRODUCT_GROUPS]);

    if (isMobile) return null;

    return (
        <nav 
            className={`flex flex-row items-center space-x-1 ${className}`}
            onMouseLeave={handleMouseLeave}
        >
             {links.map((link) => {
                 const active = isActive(link.href);
                 const isProducts = link.key === 'products';
                 const isMegaMenuOpen = isProducts && hoveredLink === 'products';

                 return (
                    <div 
                        key={link.href} 
                        className="relative"
                        onMouseEnter={() => handleMouseEnter(link.key || '')}
                    >
                        <a 
                            href={link.href} 
                            onClick={onLinkClick}
                            className={`
                                relative flex items-center justify-start gap-1 transition-colors duration-200 whitespace-nowrap
                                px-4 py-4 text-xs font-black tracking-widest text-gray-300 hover:text-white uppercase
                                ${active ? 'text-brand-orange' : ''}
                            `}
                        >
                            {link.text}
                            {isProducts && (
                                <ChevronDown 
                                    size={12} 
                                    className={`transition-transform duration-300 ease-out ${isMegaMenuOpen ? 'rotate-180 text-brand-orange' : ''}`} 
                                />
                            )}
                            <span className={`absolute bottom-3 left-4 right-4 h-[2px] bg-brand-orange transform origin-left transition-transform duration-300 ease-out ${active || hoveredLink === link.key ? 'scale-x-100' : 'scale-x-0'}`}></span>
                        </a>

                        {isProducts && (
                            <div 
                                className={`
                                    absolute left-1/2 -translate-x-1/2 w-[95vw] max-w-6xl z-[60] pt-2
                                    transition-all duration-300 cubic-bezier(0.16, 1, 0.3, 1) origin-top
                                    ${isMegaMenuOpen 
                                        ? 'opacity-100 scale-100 visible translate-y-0' 
                                        : 'opacity-0 scale-[0.98] invisible -translate-y-2 pointer-events-none'
                                    }
                                `}
                            >
                                <div className="bg-white rounded-2xl shadow-[0_40px_100px_-20px_rgba(0,0,0,0.35)] border-t-[5px] border-brand-orange overflow-hidden ring-1 ring-black/5">
                                    <div className="flex h-[420px]">

                                        {/* COL 1: SIDEBAR TÉCNICA (DEPARTAMENTOS) */}
                                        <div className="w-[260px] flex-shrink-0 bg-gray-50 border-r border-gray-100 p-3 flex flex-col gap-1">
                                            <div className="text-[9px] font-black text-gray-400 uppercase tracking-[0.25em] px-3 py-2 opacity-70">
                                                {t('layout.departments')}
                                            </div>
                                            {PRODUCT_GROUPS.map((group) => (
                                                <button
                                                    key={group.id}
                                                    onMouseEnter={() => setActiveGroup(group.id)}
                                                    className={`
                                                        text-left px-4 py-3 rounded-xl transition-all duration-150 group/btn flex items-center gap-3 relative
                                                        ${activeGroup === group.id 
                                                            ? 'bg-white shadow-md text-brand-blue-dark border border-gray-200' 
                                                            : 'text-gray-500 hover:bg-gray-200/50 hover:text-brand-blue-dark'
                                                        }
                                                    `}
                                                >
                                                    {activeGroup === group.id && (
                                                        <span className="absolute left-0 top-3 bottom-3 w-1.5 bg-brand-orange rounded-r-full"></span>
                                                    )}
                                                    <div className={`transition-colors duration-150 ${activeGroup === group.id ? 'text-brand-orange' : 'text-gray-400'}`}>
                                                        {React.cloneElement(group.icon as React.ReactElement<{ size: number }>, { size: 18 })}
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <span className="block font-black text-[13px] leading-tight mb-0.5">{group.label}</span>
                                                        <span className="block text-[9px] opacity-60 font-bold uppercase truncate">{group.description}</span>
                                                    </div>
                                                </button>
                                            ))}
                                        </div>

                                        {/* COL 2: GRADE DE PRODUTOS (ALTA DENSIDADE) */}
                                        <div className="flex-1 p-8 bg-white flex flex-col min-w-0">
                                            <div className="flex justify-between items-center mb-6 border-b border-gray-50 pb-4">
                                                <div key={activeGroup} className="animate-in fade-in slide-in-from-left-2 duration-300">
                                                    <h3 className="text-xl font-black text-brand-blue-dark tracking-tighter uppercase">
                                                        {PRODUCT_GROUPS.find(g => g.id === activeGroup)?.label}
                                                    </h3>
                                                </div>
                                                <a href="#/products" onClick={() => setHoveredLink(null)} className="text-[10px] font-black text-brand-orange hover:text-brand-blue-dark transition-colors flex items-center gap-2 group/all uppercase tracking-widest">
                                                    {t('layout.viewAll')} 
                                                    <ArrowRight size={14} className="group-hover/all:translate-x-1 transition-transform" />
                                                </a>
                                            </div>

                                            <div 
                                                key={`grid-${activeGroup}`}
                                                className="grid grid-cols-2 xl:grid-cols-3 gap-x-6 gap-y-1.5 overflow-y-auto custom-scrollbar flex-1 pr-1"
                                            >
                                                {currentGroupProducts.map((cat, idx) => (
                                                    <a 
                                                        key={cat.id} 
                                                        href={cat.href} 
                                                        onClick={() => setHoveredLink(null)} 
                                                        className="group/card flex items-center gap-3 p-1.5 rounded-xl hover:bg-brand-blue-dark/5 transition-all duration-200 border border-transparent hover:border-gray-100"
                                                    >
                                                        <div className="w-10 h-10 flex-shrink-0 rounded-lg bg-gray-100 p-0.5 overflow-hidden border border-gray-200 group-hover/card:border-brand-orange/40 transition-colors">
                                                            <img src={cat.imageUrl} alt={cat.id} className="w-full h-full object-cover rounded-md grayscale group-hover/card:grayscale-0 transition-all duration-500" loading="eager" />
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <span className="block text-[10px] font-black text-gray-700 group-hover/card:text-brand-orange transition-colors uppercase tracking-tight truncate">
                                                                {t(`productsPage.categories.${cat.id}`)}
                                                            </span>
                                                            <span className="flex items-center text-[8px] text-gray-400 font-bold uppercase tracking-tighter group-hover/card:text-brand-blue-dark">
                                                                {t('layout.viewSpecs')}
                                                                <ChevronRightIcon size={8} className="ml-1 opacity-0 group-hover/card:opacity-100 transform translate-x-[-4px] group-hover:translate-x-0 transition-all" />
                                                            </span>
                                                        </div>
                                                    </a>
                                                ))}
                                            </div>
                                        </div>

                                        {/* COL 3: PAINEL DE CATÁLOGO (PREMIUM) */}
                                        <div className="w-[300px] flex-shrink-0 bg-brand-blue-dark p-8 flex flex-col justify-between relative overflow-hidden">
                                            {/* Efeitos Visuais de Fundo */}
                                            <div className="absolute -top-20 -right-20 w-64 h-64 bg-brand-orange/20 rounded-full blur-[80px]"></div>
                                            <div className="absolute bottom-10 left-0 w-32 h-32 bg-brand-blue-light/10 rounded-full blur-[50px]"></div>

                                            <div className="relative z-10">
                                                <div className="inline-flex p-3 rounded-2xl bg-white/10 text-brand-orange mb-6 border border-white/10 shadow-inner">
                                                    <FileText size={28} />
                                                </div>
                                                <h4 className="text-xl font-black text-white mb-3 tracking-tight uppercase leading-tight">{t('layout.catalogCall')}</h4>
                                                <p className="text-[11px] text-blue-100/60 leading-relaxed font-bold uppercase tracking-wide">
                                                    {t('layout.catalogDesc')}
                                                </p>
                                            </div>

                                            <div className="relative z-10 space-y-4">
                                                <div className="flex items-center gap-3 text-[10px] text-gray-400 font-black tracking-widest uppercase">
                                                    <ShieldCheck size={16} className="text-green-500" />
                                                    <span>{t('layout.updated')}</span>
                                                </div>
                                                <a 
                                                    href="#/catalog" 
                                                    onClick={() => setHoveredLink(null)} 
                                                    className="flex items-center justify-between w-full bg-brand-orange text-white text-[11px] font-black py-4 px-6 rounded-xl hover:bg-white hover:text-brand-orange transition-all duration-300 shadow-[0_15px_30px_-5px_rgba(234,97,0,0.4)] group/cta uppercase tracking-widest"
                                                >
                                                    <span>{t('layout.downloadNow')}</span>
                                                    <ArrowRight size={18} className="group-hover/cta:translate-x-1 transition-transform" />
                                                </a>
                                            </div>
                                        </div>

                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                );
            })}
        </nav>
    );
};

