import React, { useState, useRef, useMemo, useCallback } from 'react';
import { useRouter } from '../../hooks/useRouter';
import { ChevronDown, ArrowRight, FileText, Layers, Box, Settings, Factory, ShieldCheck, ChevronRight as ChevronRightIcon } from 'lucide-react';
import { PRODUCT_CATEGORIES } from '../../lib/constants';
import { useTranslation } from 'react-i18next';

export interface NavLinkData {
    key?: string;
    text: string;
    href: string;
}

interface NavLinksProps {
  className?: string;
  links: NavLinkData[];
  onLinkClick?: () => void;
  isMobile?: boolean; 
  isScrolled?: boolean;
}

export const NavLinks: React.FC<NavLinksProps> = ({ className = '', links, onLinkClick, isMobile = false, isScrolled = false }) => {
    const { t } = useTranslation();
    const currentHash = useRouter();
    const [hoveredLink, setHoveredLink] = useState<string | null>(null);
    const [activeGroup, setActiveGroup] = useState<string>('tubular'); 
    const closeTimeoutRef = useRef<number | null>(null);

    const PRODUCT_GROUPS = useMemo(() => [
        {
            id: 'tubular',
            label: t('header.mobileGroups.tubular'),
            icon: <Layers size={16} />,
            items: ['tubes', 'conduits', 'grooved']
        },
        {
            id: 'conexoes',
            label: t('header.mobileGroups.connections'),
            icon: <Settings size={16} />,
            items: ['flanges', 'fittings', 'valves']
        },
        {
            id: 'estrutural',
            label: t('header.mobileGroups.structural'),
            icon: <Box size={16} />,
            items: ['profiles', 'plates', 'gratings', 'tiles', 'civil']
        },
        {
            id: 'industrial',
            label: t('header.mobileGroups.industrial'),
            icon: <Factory size={16} />,
            items: ['boilermaking', 'cutting', 'tanks']
        }
    ], [t]);

    const handleMouseEnter = useCallback((key: string) => {
        if (closeTimeoutRef.current) {
            clearTimeout(closeTimeoutRef.current);
            closeTimeoutRef.current = null;
        }
        setHoveredLink(key);
    }, []);

    const handleMouseLeave = useCallback(() => {
        closeTimeoutRef.current = window.setTimeout(() => {
            setHoveredLink(null);
        }, 200);
    }, []);

    const isActive = (href: string): boolean => {
        if (href === '#/') return currentHash === '' || currentHash === '#/';
        return currentHash.startsWith(href);
    };

    const currentGroupProducts = useMemo(() => {
        const group = PRODUCT_GROUPS.find(g => g.id === activeGroup);
        return group ? PRODUCT_CATEGORIES.filter(prod => group.items.includes(prod.id)) : [];
    }, [activeGroup, PRODUCT_GROUPS]);

    if (isMobile) return null;

    return (
        <nav 
            className={`flex flex-row items-center space-x-1 ${className}`}
            onMouseLeave={handleMouseLeave}
        >
             {links.map((link) => {
                 const active = isActive(link.href);
                 const isProducts = link.key === 'products';
                 const isMegaMenuOpen = isProducts && hoveredLink === 'products';

                 return (
                    <div 
                        key={link.href} 
                        className="relative"
                        onMouseEnter={() => handleMouseEnter(link.key || '')}
                    >
                        <a 
                            href={link.href} 
                            onClick={onLinkClick}
                            className={`
                                relative flex items-center justify-start gap-1 transition-colors duration-200 whitespace-nowrap
                                px-4 py-4 text-[11px] font-black tracking-widest text-gray-300 hover:text-white uppercase
                                ${active ? 'text-brand-orange' : ''}
                            `}
                        >
                            {link.text}
                            {isProducts && (
                                <ChevronDown 
                                    size={12} 
                                    className={`transition-transform duration-300 ease-out ${isMegaMenuOpen ? 'rotate-180 text-brand-orange' : ''}`} 
                                />
                            )}
                            <span className={`absolute bottom-3 left-4 right-4 h-[2px] bg-brand-orange transform origin-left transition-transform duration-300 ease-out ${active || hoveredLink === link.key ? 'scale-x-100' : 'scale-x-0'}`}></span>
                        </a>

                        {isProducts && (
                            <div 
                                className={`
                                    absolute left-1/2 -translate-x-1/2 w-[95vw] max-w-6xl z-[60] pt-1
                                    transition-all duration-300 cubic-bezier(0.16, 1, 0.3, 1) origin-top
                                    ${isMegaMenuOpen 
                                        ? 'opacity-100 scale-100 visible translate-y-0' 
                                        : 'opacity-0 scale-[0.99] invisible -translate-y-2 pointer-events-none'
                                    }
                                `}
                            >
                                <div className="bg-white rounded-2xl shadow-[0_40px_100px_-20px_rgba(0,0,0,0.5)] overflow-hidden ring-1 ring-black/10">
                                    <div className="flex h-[380px]">

                                        {/* COL 1: DEPARTAMENTOS (ESTREITO) */}
                                        <div className="w-[200px] flex-shrink-0 bg-gray-50 border-r border-gray-100 p-2 flex flex-col gap-0.5">
                                            <div className="text-[8px] font-black text-gray-400 uppercase tracking-[0.3em] px-3 py-3 opacity-60">
                                                {t('layout.departments')}
                                            </div>
                                            {PRODUCT_GROUPS.map((group) => (
                                                <button
                                                    key={group.id}
                                                    onMouseEnter={() => setActiveGroup(group.id)}
                                                    className={`
                                                        text-left px-3 py-2 rounded-lg transition-all duration-150 flex items-center gap-3 relative
                                                        ${activeGroup === group.id 
                                                            ? 'bg-white shadow-sm text-brand-blue-dark border border-gray-200' 
                                                            : 'text-gray-500 hover:text-brand-blue-dark hover:bg-gray-200/50'
                                                        }
                                                    `}
                                                >
                                                    {activeGroup === group.id && (
                                                        <span className="absolute left-0 top-2 bottom-2 w-0.5 bg-brand-orange rounded-r-full"></span>
                                                    )}
                                                    <div className={`transition-colors duration-150 ${activeGroup === group.id ? 'text-brand-orange' : 'text-gray-400'}`}>
                                                        {group.icon}
                                                    </div>
                                                    <span className="flex-1 font-bold text-[11px] leading-none uppercase tracking-tight">{group.label}</span>
                                                </button>
                                            ))}
                                        </div>

                                        {/* COL 2: LISTA TÉCNICA DE PRODUTOS (ESTILO LISTA BRUTA) */}
                                        <div className="flex-1 p-6 bg-white flex flex-col min-w-0">
                                            <div className="flex justify-between items-center mb-4 border-b border-gray-100 pb-3">
                                                <h3 className="text-sm font-black text-brand-blue-dark tracking-tighter uppercase flex items-center gap-2">
                                                    <span className="w-1 h-1 bg-brand-orange rounded-full"></span>
                                                    {PRODUCT_GROUPS.find(g => g.id === activeGroup)?.label}
                                                </h3>
                                                <a href="#/products" onClick={() => setHoveredLink(null)} className="text-[9px] font-black text-brand-orange hover:text-brand-blue-dark transition-colors flex items-center gap-1 uppercase tracking-widest group/all">
                                                    {t('layout.viewAll')} 
                                                    <ArrowRight size={10} className="group-hover/all:translate-x-1 transition-transform" />
                                                </a>
                                            </div>

                                            <div 
                                                key={`list-${activeGroup}`}
                                                className="grid grid-cols-2 gap-x-8 gap-y-0 overflow-y-auto custom-scrollbar flex-1 pr-1"
                                            >
                                                {currentGroupProducts.map((cat) => (
                                                    <a 
                                                        key={cat.id} 
                                                        href={cat.href} 
                                                        onClick={() => setHoveredLink(null)} 
                                                        className="group/item flex items-center justify-between py-2.5 border-b border-gray-50 hover:bg-gray-50 transition-colors px-2 rounded-md"
                                                    >
                                                        <div className="flex items-center gap-3 min-w-0">
                                                            <div className="w-6 h-6 flex-shrink-0 rounded bg-gray-100 p-0.5 overflow-hidden border border-gray-100 group-hover/item:border-brand-orange/40">
                                                                <img src={cat.imageUrl} alt={cat.id} className="w-full h-full object-cover rounded-sm grayscale group-hover/item:grayscale-0 transition-all" loading="eager" />
                                                            </div>
                                                            <span className="text-[11px] font-bold text-gray-600 group-hover/item:text-brand-orange transition-colors uppercase tracking-tight truncate">
                                                                {t(`productsPage.categories.${cat.id}`)}
                                                            </span>
                                                        </div>
                                                        <div className="flex items-center text-[8px] text-gray-400 font-extrabold uppercase opacity-0 group-hover/item:opacity-100 transition-opacity">
                                                            Acessar <ChevronRightIcon size={10} className="ml-1" />
                                                        </div>
                                                    </a>
                                                ))}
                                            </div>
                                        </div>

                                        {/* COL 3: PAINEL DE CATÁLOGO (ESTILO PREMIUM DA IMAGEM) */}
                                        <div className="w-[280px] flex-shrink-0 bg-[#050c21] p-8 flex flex-col justify-between relative border-t-[5px] border-brand-orange">
                                            <div className="absolute top-0 right-0 w-32 h-32 bg-brand-orange/5 rounded-full blur-[40px] pointer-events-none"></div>

                                            <div className="relative z-10">
                                                <div className="inline-flex p-3 rounded-xl bg-white/5 border border-white/10 text-brand-orange mb-5 shadow-inner">
                                                    <FileText size={24} strokeWidth={2} />
                                                </div>
                                                <h4 className="text-xl font-black text-white mb-3 tracking-tight leading-tight uppercase">
                                                    Catálogo Técnico<br/>Completo
                                                </h4>
                                                <p className="text-[10px] text-blue-100/40 leading-relaxed font-medium">
                                                    Tenha acesso a todas as tabelas de medidas, normas e especificações em um único PDF.
                                                </p>
                                            </div>

                                            <div className="relative z-10 space-y-4">
                                                <div className="flex items-center gap-2 text-[9px] text-gray-400 font-black tracking-widest uppercase">
                                                    <ShieldCheck size={14} className="text-green-500" />
                                                    <span>ATUALIZADO 2025</span>
                                                </div>
                                                <a 
                                                    href={t('productsPage.catalogPdfUrl')} 
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    onClick={() => setHoveredLink(null)} 
                                                    className="flex items-center justify-between w-full bg-brand-orange text-white text-[11px] font-black py-3.5 px-5 rounded-xl hover:bg-white hover:text-brand-orange transition-all duration-300 shadow-[0_15px_30px_-5px_rgba(234,97,0,0.35)] group/cta uppercase tracking-widest"
                                                >
                                                    <span>BAIXAR AGORA</span>
                                                    <ArrowRight size={18} className="group-hover/cta:translate-x-1 transition-transform" />
                                                </a>
                                            </div>
                                        </div>

                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                );
            })}
        </nav>
    );
};

import React from 'react';
import { useRouter } from '../../hooks/useRouter';
import { useTranslation } from 'react-i18next';

export interface NavLinkData {
    key?: string;
    text: string;
    href: string;
}

interface NavLinksProps {
  className?: string;
  links: NavLinkData[];
  onLinkClick?: () => void;
  isMobile?: boolean; 
  isScrolled?: boolean;
}

export const NavLinks: React.FC<NavLinksProps> = ({ className = '', links, onLinkClick, isMobile = false }) => {
    const { t } = useTranslation();
    const currentHash = useRouter();

    const isActive = (href: string): boolean => {
        if (href === '#/') return currentHash === '' || currentHash === '#/';
        return currentHash.startsWith(href);
    };

    if (isMobile) return null;

    return (
        <nav className={`flex flex-row items-center space-x-1 ${className}`}>
             {links.map((link) => {
                 const active = isActive(link.href);

                 return (
                    <div key={link.href} className="relative group">
                        <a 
                            href={link.href} 
                            onClick={onLinkClick}
                            className={`
                                relative flex items-center justify-start gap-1 transition-colors duration-200 whitespace-nowrap
                                px-4 py-4 text-[11px] font-black tracking-widest text-gray-300 hover:text-white uppercase
                                ${active ? 'text-brand-orange' : ''}
                            `}
                        >
                            {link.text}
                            <span className={`absolute bottom-3 left-4 right-4 h-[2px] bg-brand-orange transform origin-left transition-transform duration-300 ease-out ${active ? 'scale-x-100' : 'scale-x-0 group-hover:scale-x-100'}`}></span>
                        </a>
                    </div>
                );
            })}
        </nav>
    );
};
